	eventId: varchar({ length: 255 }).notNull(),
	// The user who registered (captain for team registrations)
	userId: varchar({ length: 255 }).notNull(),
	// The team membership created in the competition_event team
	teamMemberId: varchar({ length: 255 }).notNull(),
	// The division (scaling level) the athlete is competing in
	divisionId: varchar({ length: 255 }),
	// When the athlete registered
	registeredAt: datetime().notNull(),
	// Registration status: active = participating, removed = soft-deleted by organizer
	status: varchar({ length: 20 })
		.$type<RegistrationStatus>()
		.default("active")
		.notNull(),
	// Team info (NULL for individual registrations)
	teamName: varchar({ length: 255 }),
	// Who created the registration (same as userId for individuals)
	captainUserId: varchar({ length: 255 }),
	// For team registrations, the athlete team (competition_team type)
	// NULL for individual registrations (teamSize=1)
	athleteTeamId: varchar({ length: 255 }),
	// Pending teammates stored as JSON until they accept
	// Format: [{ email, firstName?, lastName?, affiliateName? }, ...]
	pendingTeammates: text(), // JSON array
	// Metadata as JSON (flexible for future expansion)
	metadata: text(), // JSON: { notes: "..." }

	// Commerce: Payment tracking
	// Reference to commerce_purchase (no FK to avoid circular deps - relation defined separately)
	commercePurchaseId: varchar({ length: 255 }),
	// Payment status: FREE | PENDING_PAYMENT | PAID | FAILED
	paymentStatus: varchar({ length: 20 }),
	// When payment was completed
	paidAt: datetime(),
},
(table) => [
	// One user can only register once per division per competition
	uniqueIndex("competition_registrations_event_user_division_idx").on(
		table.eventId,
		table.userId,
		table.divisionId,
	),
	index("competition_registrations_user_idx").on(table.userId),
	index("competition_registrations_event_idx").on(table.eventId),
	index("competition_registrations_division_idx").on(table.divisionId),
	index("competition_registrations_captain_idx").on(table.captainUserId),
	index("competition_registrations_athlete_team_idx").on(table.athleteTeamId),
	index("competition_registrations_purchase_idx").on(
		table.commercePurchaseId,
	),

const removeRegistrationInputSchema = z.object({
	registrationId: z.string().min(1, "Registration ID is required"),
	competitionId: z.string().min(1, "Competition ID is required"),
})

/**
 * Remove a registration (soft delete) by an organizer.
 *
 * Sets the registration status to REMOVED and deactivates associated
 * team memberships, heat assignments, and pending invitations.
 * Requires MANAGE_COMPETITIONS permission on the organizing team.
 */
export const removeRegistrationFn = createServerFn({ method: "POST" })
	.inputValidator((data: unknown) => removeRegistrationInputSchema.parse(data))
	.handler(async ({ data: input }) => {
		const session = await getSessionFromCookie()
		if (!session?.userId) throw new Error("Unauthorized")

		const db = getDb()

		updateRequestContext({ userId: session.userId })
		addRequestContextAttribute("competitionId", input.competitionId)
		addRequestContextAttribute("registrationId", input.registrationId)

		// 1. Get competition to verify ownership and get organizing team
		const competition = await db.query.competitionsTable.findFirst({
			where: eq(competitionsTable.id, input.competitionId),
			columns: { id: true, organizingTeamId: true },
		})

		if (!competition) throw new Error("Competition not found")

		// 2. Require organizer permission (site admins bypass)
		if (session.user?.role !== ROLES_ENUM.ADMIN) {
			const team = session.teams?.find(
				(t) => t.id === competition.organizingTeamId,
			)
			if (!team?.permissions.includes(TEAM_PERMISSIONS.MANAGE_COMPETITIONS)) {
				throw new Error("Missing required permission: manage_competitions")
			}
		}

		// 3. Get the registration and verify it belongs to this competition
		const registration = await db.query.competitionRegistrationsTable.findFirst(
			{
				where: and(
					eq(competitionRegistrationsTable.id, input.registrationId),
					eq(competitionRegistrationsTable.eventId, input.competitionId),
				),
			},
		)

		if (!registration) throw new Error("Registration not found")

		if (registration.status === REGISTRATION_STATUS.REMOVED) {
			throw new Error("Registration is already removed")
		}

		logInfo({
			message: "[Registration] Removing registration",
			attributes: {
				registrationId: input.registrationId,
				competitionId: input.competitionId,
				userId: registration.userId,
				athleteTeamId: registration.athleteTeamId ?? "none",
			},
		})

		// 4. Set registration status to REMOVED
		await db
			.update(competitionRegistrationsTable)
			.set({
				status: REGISTRATION_STATUS.REMOVED,
				updatedAt: new Date(),
			})
			.where(eq(competitionRegistrationsTable.id, input.registrationId))

		// 5. Deactivate the captain's team membership in the competition_event team
		await db
			.update(teamMembershipTable)
			.set({ isActive: false })
			.where(eq(teamMembershipTable.id, registration.teamMemberId))

		// 6. For team registrations, deactivate all athlete team memberships and cancel invitations
		if (registration.athleteTeamId) {
			// Deactivate all memberships on the athlete team
			await db
				.update(teamMembershipTable)
				.set({ isActive: false })
				.where(
					and(
						eq(teamMembershipTable.teamId, registration.athleteTeamId),
						eq(teamMembershipTable.isActive, true),
					),
				)

			// Cancel pending invitations for the athlete team
			const { INVITATION_STATUS } = await import("@/db/schema")
			await db
				.update(teamInvitationTable)
				.set({ status: INVITATION_STATUS.CANCELLED })
				.where(
					and(
						eq(teamInvitationTable.teamId, registration.athleteTeamId),
						eq(teamInvitationTable.status, INVITATION_STATUS.PENDING),
					),
				)
		}

		// 7. Delete heat assignments for this registration
		await db
			.delete(competitionHeatAssignmentsTable)
			.where(
				eq(
					competitionHeatAssignmentsTable.registrationId,
					input.registrationId,
				),
			)

		// 8. Delete scores for the registered user(s) in this competition's events
		const { scoresTable, competitionEventsTable } = await import("@/db/schema")

		// Get all competition event IDs
		const competitionEvents = await db
			.select({ id: competitionEventsTable.id })
			.from(competitionEventsTable)
			.where(eq(competitionEventsTable.competitionId, input.competitionId))

		if (competitionEvents.length > 0) {
			const eventIds = competitionEvents.map((e) => e.id)

			// Collect all user IDs to clean up scores for
			const userIds = [registration.userId]

			// For team registrations, also get teammate user IDs
			if (registration.athleteTeamId) {
				const teammates = await db
					.select({ userId: teamMembershipTable.userId })
					.from(teamMembershipTable)
					.where(eq(teamMembershipTable.teamId, registration.athleteTeamId))

				for (const tm of teammates) {
					if (tm.userId && !userIds.includes(tm.userId)) {
						userIds.push(tm.userId)
					}
				}
			}

			// Delete scores for these users in this competition's events
			for (const eventId of eventIds) {
				for (const userId of userIds) {
					await db
						.delete(scoresTable)
						.where(
							and(
								eq(scoresTable.competitionEventId, eventId),
								eq(scoresTable.userId, userId),
							),
						)
				}
			}
		}

		logInfo({
			message: "[Registration] Registration removed successfully",
			attributes: {
				registrationId: input.registrationId,
				competitionId: input.competitionId,
				userId: registration.userId,
			},
		})

		return { success: true }
	})

// Users CAN register for multiple divisions in the same competition
// Exclude removed registrations so athletes can re-register after removal
const existingRegistration =
	await db.query.competitionRegistrationsTable.findFirst({
		where: and(
			eq(competitionRegistrationsTable.eventId, params.competitionId),
			eq(competitionRegistrationsTable.userId, params.userId),
			eq(competitionRegistrationsTable.divisionId, params.divisionId),
			ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
		),
	})

if (existingRegistration) {
	throw new Error(
		"You are already registered for this division in this competition",
	)
}

// 8b. Check if user is already on another team for this DIVISION (as teammate)
// Users can be on different teams in different divisions
const existingTeamMembership = await db
	.select({ teamId: teamMembershipTable.teamId })
	.from(teamMembershipTable)
	.innerJoin(teamTable, eq(teamMembershipTable.teamId, teamTable.id))
	.where(
		and(
			eq(teamMembershipTable.userId, params.userId),
			eq(teamMembershipTable.isActive, true),
			eq(teamTable.type, TEAM_TYPE_ENUM.COMPETITION_TEAM),
			sql`JSON_EXTRACT(${teamTable.competitionMetadata}, '$.competitionId') = ${params.competitionId}`,
			sql`JSON_EXTRACT(${teamTable.competitionMetadata}, '$.divisionId') = ${params.divisionId}`,
		),
	)
	.limit(1)

if (existingTeamMembership.length > 0) {
	throw new Error("You are already on a team for this division")
}

// 8c. Check if user's email is in pendingTeammates of another registration in the SAME division
if (user.email) {
	const pendingMatch = await db
		.select({ id: competitionRegistrationsTable.id })
		.from(competitionRegistrationsTable)
		.where(
			and(
				eq(competitionRegistrationsTable.eventId, params.competitionId),
				eq(competitionRegistrationsTable.divisionId, params.divisionId),
				sql`JSON_CONTAINS(${competitionRegistrationsTable.pendingTeammates}, JSON_OBJECT('email', ${user.email.toLowerCase()}))`,
			),
		)
		.limit(1)

	if (pendingMatch.length > 0) {
		throw new Error(
			"You have already been invited to another team for this division",
		)
	}
}

	),
	columns: { teamId: true },
})

const userTeamIds = userTeamMemberships.map((m) => m.teamId)

// Get team registrations
const teamRegistrations =
	userTeamIds.length > 0
		? await db.query.competitionRegistrationsTable.findMany({
				where: inArray(
					competitionRegistrationsTable.athleteTeamId,
					userTeamIds,
				),
				with: {
					competition: {
						with: {
							organizingTeam: true,
						},
					},
					division: true,
					athleteTeam: true,
				},
				orderBy: (table, { desc }) => [desc(table.registeredAt)],
			})
		: []

// Combine and deduplicate by registration ID
const allRegistrations = [...directRegistrations, ...teamRegistrations]
const seenIds = new Set<string>()
const competitionHistory = allRegistrations
	.filter((reg) => {
		if (seenIds.has(reg.id)) return false
		seenIds.add(reg.id)
		return true
	})
	.sort((a, b) => {
		const aDate = new Date(a.registeredAt).getTime()
		const bDate = new Date(b.registeredAt).getTime()
		return bDate - aDate

		search: { redirect: "/compete/athlete" },
	})
}

// Get sponsors
const sponsorsResult = await getUserSponsorsFn({
	data: { userId: session.userId },
})

// Get direct registrations (user is captain)
const directRegistrations =
	await db.query.competitionRegistrationsTable.findMany({
		where: eq(competitionRegistrationsTable.userId, session.userId),
		with: {
			competition: {
				with: {
					organizingTeam: true,
				},
			},
			division: true,
			athleteTeam: true,
		},
		orderBy: (table, { desc }) => [desc(table.registeredAt)],
	})

// Get team registrations (user is teammate)
const userTeamMemberships = await db.query.teamMembershipTable.findMany({
	where: and(
		eq(teamMembershipTable.userId, session.userId),
		eq(teamMembershipTable.isActive, true),

		scalingLevelsTable,
		eq(competitionRegistrationsTable.divisionId, scalingLevelsTable.id),
	)
	.where(
		and(
			eq(competitionRegistrationsTable.eventId, data.competitionId),
			ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
			...(data.divisionId
				? [eq(competitionRegistrationsTable.divisionId, data.divisionId)]
				: []),
		),
	)

const filteredRegistrations = registrations

// Get existing scores for this event
const userIds = filteredRegistrations.map((r) => r.user.id)
const existingScores =
	userIds.length > 0
		? await db
				.select()
				.from(scoresTable)
				.where(
					and(
						eq(scoresTable.competitionEventId, data.trackWorkoutId),
						inArray(scoresTable.userId, userIds),
					),
				)
		: []

// Get score_rounds for all existing scores
const scoreIds = existingScores.map((s) => s.id)
const existingRounds =
	scoreIds.length > 0
		? await db
				.select({
					scoreId: scoreRoundsTable.scoreId,
					roundNumber: scoreRoundsTable.roundNumber,
					value: scoreRoundsTable.value,
				})

					.innerJoin(
						competitionRegistrationsTable,
						eq(
							competitionHeatAssignmentsTable.registrationId,
							competitionRegistrationsTable.id,
						),
					)
					.where(
						inArray(competitionHeatAssignmentsTable.heatId, mixedHeatIds),
					)
			: []

	const relevantIds = getRelevantWorkoutIds({
		heats: heatsForWorkouts,
		mixedHeatAssignments,
		divisionId: params.divisionId,
	})

	if (relevantIds) {
		filteredTrackWorkouts = trackWorkouts.filter((tw) =>
			relevantIds.has(tw.id),
		)

		if (filteredTrackWorkouts.length === 0) {
			return { entries: [], scoringConfig, events: [] }
		}
	}
}

// Get all registrations for this competition
const registrations = await db
	.select({
		registration: competitionRegistrationsTable,
		user: userTable,
		division: scalingLevelsTable,
	})
	.from(competitionRegistrationsTable)
	.innerJoin(
		userTable,
		eq(competitionRegistrationsTable.userId, userTable.id),
	)
	.leftJoin(
		scalingLevelsTable,
		eq(competitionRegistrationsTable.divisionId, scalingLevelsTable.id),
	)
	.where(
	and(
		eq(competitionRegistrationsTable.eventId, params.competitionId),
		ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
	),
)

if (registrations.length === 0) {
	const events = filteredTrackWorkouts.map((tw) => ({
		trackWorkoutId: tw.id,
		name: tw.workout.name,
	}))
	return { entries: [], scoringConfig, events }
}

// Filter by division if specified
const filteredRegistrations = params.divisionId
	? registrations.filter(
			(r) => r.registration.divisionId === params.divisionId,
		)
	: registrations

// Get team members for team registrations
const athleteTeamIds = filteredRegistrations
	.filter(
		(r) => r.registration.athleteTeamId && (r.division?.teamSize ?? 1) > 1,
	)
	.map((r) => r.registration.athleteTeamId as string)

const allTeamMemberships =
	athleteTeamIds.length > 0
		? await db
				.select({
					membership: teamMembershipTable,
					user: userTable,
				})
				.from(teamMembershipTable)
				.innerJoin(userTable, eq(teamMembershipTable.userId, userTable.id))
				.where(inArray(teamMembershipTable.teamId, athleteTeamIds))
		: []

// Group memberships by teamId
const membershipsByTeamId = new Map<
	string,
	Array<{
		membership: (typeof allTeamMemberships)[number]["membership"]
		user: (typeof allTeamMemberships)[number]["user"]
	}>
>()
for (const m of allTeamMemberships) {
	const teamId = m.membership.teamId
	const existing = membershipsByTeamId.get(teamId) || []
	existing.push(m)
	membershipsByTeamId.set(teamId, existing)
}

		let teamRegistrations: typeof directRegistrations = []
		if (userTeamMemberships.length > 0) {
			const userTeamIds = userTeamMemberships.map((m) => m.teamId)

			teamRegistrations = await db
				.select(registrationColumns)
				.from(competitionRegistrationsTable)
				.where(
					and(
						eq(competitionRegistrationsTable.eventId, data.competitionId),
						sql`${competitionRegistrationsTable.athleteTeamId} IN (${sql.join(
							userTeamIds.map((id) => sql`${id}`),
							sql`, `,
						)})`,
					),
				)
		}

		// Merge and deduplicate (a captain appears in both direct and team sets)
		const seenIds = new Set<string>()
		const allRegistrations: typeof directRegistrations = []

		for (const reg of [...directRegistrations, ...teamRegistrations]) {
			if (!seenIds.has(reg.id)) {
				seenIds.add(reg.id)
				allRegistrations.push(reg)
			}
		}

		return { registrations: allRegistrations }
	})

/**
 * Get pending team invitations for a user related to a competition
 * Used to show invites to join competition teams
 */
export const getPendingTeamInvitesFn = createServerFn({ method: "GET" })
	.inputValidator((data: unknown) =>
		getPendingTeamInvitesInputSchema.parse(data),

																(a) => a.questionId === question.id,
															)
														return (
															<TableCell key={question.id} className="text-sm">
																{pendingAnswer?.answer ?? "—"}
															</TableCell>
														)
													}
													// For registered members, get from registration answers
													const answers = getAnswersForUser(
														row.registrationId,
														row.athlete.id,
													)
													const answer = answers.find(
														(a) => a.questionId === question.id,
													)
													return (
														<TableCell key={question.id} className="text-sm">
															{answer?.answer ?? "—"}
														</TableCell>
													)
												})}
												{waivers.map((waiver) => {
													// For pending/accepted invites, check pending signatures
													if (
														row.status !== "registered" &&
														row.pendingInvite
													) {
														const pendingSig =
															row.pendingInvite.pendingSignatures?.find(
																(s) => s.waiverId === waiver.id,
															)
														return (
															<TableCell key={waiver.id} className="text-sm">
																{pendingSig ? (
																	<span className="text-green-600">
																		{formatDate(pendingSig.signedAt)}
																	</span>
																) : (
																	<span className="text-muted-foreground">
																		Not signed
																	</span>
																)}
															</TableCell>
														)
													}
													// For registered members, get from waiver signatures
													const signedDate = getWaiverSignedDate(
														row.athlete.id,
														waiver.id,
													)
													return (
														<TableCell key={waiver.id} className="text-sm">
															{signedDate ? (
																<span className="text-green-600">
																	{formatDate(signedDate)}
																</span>
															) : (
																<span className="text-muted-foreground">
																	Not signed
																</span>
															)}
														</TableCell>
													)
												})}
												<TableCell className="text-muted-foreground text-sm">
													{row.registeredAt
														? formatDate(row.registeredAt)
														: null}
												</TableCell>
												<TableCell className="text-muted-foreground text-sm">
													{row.joinedAt ? formatDate(row.joinedAt) : null}
												</TableCell>
												<TableCell>
													{row.isCaptain && !isRowRemoved && (
														<DropdownMenu>
															<DropdownMenuTrigger asChild>
																<Button
																	variant="ghost"
																	size="icon"
																	className="h-8 w-8"
																>
																	<MoreHorizontal className="h-4 w-4" />
																</Button>
															</DropdownMenuTrigger>
															<DropdownMenuContent align="end">
																<DropdownMenuItem
																	className="text-destructive focus:text-destructive"
																	onClick={() =>
																		setRemovingRegistration({
																			id: row.registrationId,
																			athleteName:
																				`${row.athlete.firstName ?? ""} ${row.athlete.lastName ?? ""}`.trim() ||
																				row.athlete.email ||
																				"Unknown",
																			teamName: row.teamName,
																		})
																	}
																>
																	<Trash2 className="h-4 w-4 mr-2" />
																	Remove Registration
																</DropdownMenuItem>
															</DropdownMenuContent>
														</DropdownMenu>
													)}
												</TableCell>
											</TableRow>
										)
									})}
									</TableBody>
								</Table>
							</CardContent>
						</Card>
					)}
				</div>
			)}
		</div>

		<AlertDialog
			open={!!removingRegistration}
			onOpenChange={(open) => !open && setRemovingRegistration(null)}
		>
			<AlertDialogContent>
				<AlertDialogHeader>
					<AlertDialogTitle>Remove Registration</AlertDialogTitle>
					<AlertDialogDescription>
						Are you sure you want to remove the registration for{" "}
						<strong>{removingRegistration?.athleteName}</strong>
						{removingRegistration?.teamName && (
							<> (team: {removingRegistration.teamName})</>
						)}
						? This will remove them from the competition, delete their heat
						assignments and scores. This action cannot be undone.
					</AlertDialogDescription>
				</AlertDialogHeader>
				<AlertDialogFooter>
					<AlertDialogCancel disabled={isRemoving}>Cancel</AlertDialogCancel>
					<AlertDialogAction
						onClick={handleRemoveRegistration}
						disabled={isRemoving}
						className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
					>
						{isRemoving ? "Removing..." : "Remove Registration"}
					</AlertDialogAction>
				</AlertDialogFooter>
			</AlertDialogContent>
		</AlertDialog>
		</>
	)
}

