				.optional(),
			murph: z
				.object({ time: z.string().optional(), date: z.string().optional() })
				.optional(),
			row2k: z
				.object({ time: z.string().optional(), date: z.string().optional() })
				.optional(),
			run1Mile: z
				.object({ time: z.string().optional(), date: z.string().optional() })
				.optional(),
			run5k: z
				.object({ time: z.string().optional(), date: z.string().optional() })
				.optional(),
