					division: {
						columns: {
							id: true,
							label: true,
							teamSize: true,
						},
					},
					athleteTeam: {
						with: {
							memberships: {
								columns: {
									id: true,
									userId: true,
									joinedAt: true,
								},
								where: eq(teamMembershipTable.isActive, true),
								with: {
