	)
	.handler(async ({ data }) => {
		const { getDb } = await import("@/db")
		const db = getDb()
		const user = await db.query.userTable.findFirst({
			where: eq(userTable.id, data.userId),
			columns: {
				affiliateName: true,
				firstName: true,
				lastName: true,
				email: true,
			},
		})

